1685                     << " with current MemoryAccess leader ");
1686   LLVM_DEBUG(dbgs() << *NewClass->getMemoryLeader() << "\n");
1687 
1688   auto LookupResult = MemoryAccessToClass.find(From);
1689   bool Changed = false;
